import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats').then(r=>{setStats(r.data.data);setLoading(false);}).catch(()=>setLoading(false));
  }, []);

  if (loading) return (
    <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'100vh'}}>
      <div style={{textAlign:'center'}}>
        <div style={{width:40,height:40,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite',margin:'0 auto 12px'}}/>
        <p style={{color:'rgba(255,255,255,0.3)',fontSize:13}}>Loading...</p>
      </div>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );

  const cards = [
    { label:'Total Books',    value:stats?.totalBooks||0,    icon:'📚', color:'#6366f1', glow:'rgba(99,102,241,0.15)',  sub:'Library'  },
    { label:'Active Members', value:stats?.totalMembers||0,  icon:'👥', color:'#10b981', glow:'rgba(16,185,129,0.15)', sub:'Enrolled' },
    { label:'Books Out',      value:stats?.activeBorrows||0, icon:'📤', color:'#c9a84c', glow:'rgba(201,168,76,0.15)', sub:'Active'   },
    { label:'Overdue',        value:stats?.overdueBorrows||0,icon:'⚠️', color:'#ef4444', glow:'rgba(239,68,68,0.15)',  sub:'Urgent'   },
  ];

  return (
    <div className="page-enter" style={{padding:'36px 40px',maxWidth:1200}}>
      <style>{`
        .stat-card { transition: all .25s !important; }
        .stat-card:hover { transform:translateY(-4px) !important; box-shadow:0 16px 48px rgba(0,0,0,0.4) !important; }
        .alert-card { transition:background .2s !important; }
        .alert-card:hover { filter:brightness(1.1); }
        .list-row { transition:background .15s !important; }
        .list-row:hover { background:rgba(255,255,255,0.04) !important; }
      `}</style>

      {/* ── Header ── */}
      <div style={{marginBottom:36,display:'flex',alignItems:'flex-start',justifyContent:'space-between'}}>
        <div>
          <p style={{fontSize:12,color:'rgba(255,255,255,0.25)',letterSpacing:'1.5px',textTransform:'uppercase',marginBottom:8}}>
            {new Date().toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}
          </p>
          <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:36,fontWeight:700,color:'#fff',lineHeight:1.1,letterSpacing:'-0.5px'}}>
            Good day, {user?.name?.split(' ')[0]} 👋
          </h1>
        </div>
        <div style={{background:'rgba(255,255,255,0.04)',border:'1px solid rgba(255,255,255,0.07)',borderRadius:12,padding:'12px 18px',textAlign:'right'}}>
          <div style={{fontSize:11,color:'rgba(255,255,255,0.25)',marginBottom:4,letterSpacing:'1px',textTransform:'uppercase'}}>Logged in as</div>
          <div style={{fontSize:15,fontWeight:700,color:'#c9a84c',textTransform:'capitalize'}}>{user?.role==='librarian'?'Head Librarian':user?.role==='library_assistant'?'Library Assistant':user?.role}</div>
        </div>
      </div>

      {/* ── Alerts ── */}
      {isStaff && stats && stats.pendingMembers>0 && (
        <div className="alert-card" onClick={()=>navigate('/members?status=pending')} style={{background:'rgba(245,158,11,0.08)',border:'1px solid rgba(245,158,11,0.2)',borderRadius:14,padding:'16px 22px',marginBottom:16,display:'flex',alignItems:'center',gap:16,cursor:'pointer'}}>
          <div style={{width:42,height:42,background:'rgba(245,158,11,0.15)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',fontSize:20,flexShrink:0}}>⏳</div>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:700,color:'#fbbf24'}}>{stats.pendingMembers} account(s) waiting for approval</div>
            <div style={{fontSize:13,color:'rgba(251,191,36,0.5)',marginTop:3}}>Click to review and approve members</div>
          </div>
          <span style={{color:'rgba(251,191,36,0.4)',fontSize:22}}>→</span>
        </div>
      )}
      {isStaff && stats && stats.pendingRequests>0 && (
        <div className="alert-card" onClick={()=>navigate('/requests')} style={{background:'rgba(99,102,241,0.08)',border:'1px solid rgba(99,102,241,0.2)',borderRadius:14,padding:'16px 22px',marginBottom:24,display:'flex',alignItems:'center',gap:16,cursor:'pointer'}}>
          <div style={{width:42,height:42,background:'rgba(99,102,241,0.15)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',fontSize:20,flexShrink:0}}>🔔</div>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:700,color:'#a5b4fc'}}>{stats.pendingRequests} borrow request(s) pending</div>
            <div style={{fontSize:13,color:'rgba(165,180,252,0.5)',marginTop:3}}>Click to review and approve requests</div>
          </div>
          <span style={{color:'rgba(165,180,252,0.4)',fontSize:22}}>→</span>
        </div>
      )}

      {stats && (
        <>
          {/* ── Stat Cards ── */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:18,marginBottom:32}}>
            {cards.map(c=>(
              <div key={c.label} className="stat-card" style={{background:'#12122a',border:'1px solid rgba(255,255,255,0.06)',borderRadius:20,padding:'24px 22px 20px',cursor:'default',position:'relative',overflow:'hidden'}}>
                {/* glow bg */}
                <div style={{position:'absolute',top:-20,right:-20,width:100,height:100,background:c.glow,borderRadius:'50%',filter:'blur(30px)',pointerEvents:'none'}}/>
                <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:20,position:'relative'}}>
                  <div style={{width:46,height:46,borderRadius:13,background:c.color+'18',border:`1px solid ${c.color}30`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:21}}>{c.icon}</div>
                  <span style={{fontSize:11,fontWeight:700,padding:'4px 12px',borderRadius:99,background:c.color+'18',color:c.color,letterSpacing:'.5px'}}>{c.sub}</span>
                </div>
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:44,fontWeight:700,color:'#fff',lineHeight:1,marginBottom:6,position:'relative'}}>{c.value}</div>
                <div style={{fontSize:13,color:'rgba(255,255,255,0.35)',fontWeight:500,position:'relative'}}>{c.label}</div>
                <div style={{marginTop:16,height:3,background:'rgba(255,255,255,0.05)',borderRadius:99,overflow:'hidden'}}>
                  <div style={{height:'100%',width:c.value>0?'60%':'8%',background:`linear-gradient(90deg,${c.color},${c.color}88)`,borderRadius:99,transition:'width 1.2s ease'}}/>
                </div>
              </div>
            ))}
          </div>

          {/* ── Bottom Panels ── */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:22}}>
            {/* Recent Borrows */}
            <div style={{background:'#12122a',border:'1px solid rgba(255,255,255,0.06)',borderRadius:20,padding:26}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:22}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:19,fontWeight:700,color:'#fff'}}>Recent Borrows</h3>
                <span style={{fontSize:11,color:'rgba(255,255,255,0.25)',background:'rgba(255,255,255,0.05)',border:'1px solid rgba(255,255,255,0.07)',padding:'4px 12px',borderRadius:99}}>Latest 5</span>
              </div>
              {stats.recentBorrows.length ? stats.recentBorrows.map((b:any)=>(
                <div key={b.id} className="list-row" style={{display:'flex',alignItems:'center',gap:14,padding:'12px 14px',borderRadius:12,marginBottom:6,border:'1px solid transparent',cursor:'default'}}>
                  <div style={{width:38,height:38,background:'rgba(201,168,76,0.1)',border:'1px solid rgba(201,168,76,0.15)',borderRadius:10,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:17}}>📗</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:600,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.3)',marginTop:2}}>{b.member_name} · <span style={{textTransform:'capitalize'}}>{b.account_type}</span></div>
                  </div>
                  <span style={{fontSize:11,fontWeight:700,padding:'4px 10px',borderRadius:99,flexShrink:0,textTransform:'capitalize',
                    background:b.status==='returned'?'rgba(16,185,129,0.12)':b.status==='overdue'?'rgba(239,68,68,0.12)':'rgba(245,158,11,0.12)',
                    color:b.status==='returned'?'#34d399':b.status==='overdue'?'#f87171':'#fbbf24'
                  }}>{b.status}</span>
                </div>
              )) : (
                <div style={{textAlign:'center',padding:'36px 0',color:'rgba(255,255,255,0.2)'}}>
                  <div style={{fontSize:36,marginBottom:10}}>📭</div>
                  <p style={{fontSize:14}}>No borrows yet</p>
                </div>
              )}
            </div>

            {/* Popular Books */}
            <div style={{background:'#12122a',border:'1px solid rgba(255,255,255,0.06)',borderRadius:20,padding:26}}>
              <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:22}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:19,fontWeight:700,color:'#fff'}}>Popular Books</h3>
                <span style={{fontSize:11,color:'rgba(255,255,255,0.25)',background:'rgba(255,255,255,0.05)',border:'1px solid rgba(255,255,255,0.07)',padding:'4px 12px',borderRadius:99}}>Top 5</span>
              </div>
              {stats.popularBooks.length ? stats.popularBooks.map((b:any,i:number)=>(
                <div key={b.title} className="list-row" style={{display:'flex',alignItems:'center',gap:14,padding:'12px 14px',borderRadius:12,marginBottom:6,border:'1px solid transparent',cursor:'default'}}>
                  <div style={{width:32,height:32,borderRadius:9,flexShrink:0,display:'flex',alignItems:'center',justifyContent:'center',fontSize:13,fontWeight:800,
                    background:i===0?'linear-gradient(135deg,#c9a84c,#b8962f)':i===1?'rgba(156,163,175,0.15)':i===2?'rgba(180,120,60,0.15)':'rgba(255,255,255,0.05)',
                    color:i===0?'#1a1a2e':i===1?'#9ca3af':i===2?'#b4783c':'rgba(255,255,255,0.3)',
                    boxShadow:i===0?'0 4px 12px rgba(201,168,76,0.4)':'none'
                  }}>{i+1}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:600,color:'#fff',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:12,color:'rgba(255,255,255,0.3)',marginTop:2}}>{b.author}</div>
                  </div>
                  <div style={{fontSize:15,fontWeight:800,color:'#c9a84c',flexShrink:0}}>{b.borrow_count}×</div>
                </div>
              )) : (
                <div style={{textAlign:'center',padding:'36px 0',color:'rgba(255,255,255,0.2)'}}>
                  <div style={{fontSize:36,marginBottom:10}}>📊</div>
                  <p style={{fontSize:14}}>No data yet</p>
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
